import { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import "../App.css";
import Nav from "../components/Nav";
import API from "../api/axios";
import { useAuth } from "../context/AuthContext";

export default function HomePage() {
  const [darkMode, setDarkMode] = useState(false);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  const [commentText, setCommentText] = useState({});
  const { user } = useAuth();
  const navigate = useNavigate();

  /* =============================
     THEME LOAD
  ============================= */
  useEffect(() => {
    const savedTheme = localStorage.getItem("user-theme");

    if (savedTheme === "dark") {
      document.body.classList.add("dark-mode");
      setDarkMode(true);
    } else {
      document.body.classList.remove("dark-mode");
      setDarkMode(false);
    }
  }, []);

  /* =============================
     FETCH POSTS
  ============================= */
  useEffect(() => {
    API.get("/posts")
      .then((res) => setPosts(res.data))
      .catch((err) => console.error(err))
      .finally(() => setLoading(false));
  }, []);

  /* =============================
     ROLE HELPERS
  ============================= */
  const role = user?.role?.toLowerCase?.() || "";
  const isAdmin = role === "admin";

  const canEdit = (post) => {
    return (
      isAdmin ||
      post.author?._id === user?._id // owner check
    );
  };

  /* =============================
     COMMENT HANDLER (UI ONLY)
  ============================= */
  const handleComment = (postId) => {
    const text = commentText[postId];
    if (!text) return;

    console.log("Comment:", postId, text);

    setCommentText((prev) => ({
      ...prev,
      [postId]: "",
    }));
  };

  return (
    <>
      <Nav />

      <main className="content-wrapper">

        {/* HERO SECTION (UNCHANGED) */}
        <section className="hero">
          <div className="image-container">
            <a href="/pictures/light-mode-pic.png">
              <img
                src="/pictures/light-mode-pic.png"
                className="light-img theme-img"
                alt="Profile Light"
              />

              <img
                src="/pictures/dark-mode-pic.png"
                className="dark-img theme-img"
                alt="Profile Dark"
              />
            </a>
          </div>

          <div className="intro">
            <h2>HELLO, I'M CLAIRE</h2>
            <p>
              Welcome to my art portfolio...
            </p>
          </div>
        </section>

        {/* POSTS SECTION */}
        <section className="posts-section">
          <h2>Latest Posts</h2>

          {loading && <p>Loading posts...</p>}

          {!loading && posts.length === 0 && (
            <p>No posts yet. Be the first to write one!</p>
          )}

          <div className="posts-grid">

            {posts.map((post) => (
              <div key={post._id} className="post-card">

                {/* IMAGE */}
                {post.image && (
                  <img
                    src={`http://localhost:5000/uploads/${post.image}`}
                    alt={post.title}
                    onClick={() => navigate(`/posts/${post._id}`)}
                    style={{ cursor: "pointer" }}
                  />
                )}

                {/* TITLE (CLICKABLE) */}
                <h3>
                  <Link to={`/posts/${post._id}`}>
                    {post.title}
                  </Link>
                </h3>

                <p>{post.body.substring(0, 120)}...</p>

                <small>
                  By {post.author?.name} ·{" "}
                  {new Date(post.createdAt).toLocaleDateString()}
                </small>

                {/* =========================
                    EDIT BUTTON (OWNER + ADMIN ONLY)
                ========================= */}
                {canEdit(post) && (
                  <button
                    className="edit-btn"
                    onClick={() => navigate(`/edit-post/${post._id}`)}
                  >
                    ✏️ Edit
                  </button>
                )}

                {/* =========================
                    COMMENT SECTION
                ========================= */}
                <div className="comment-box">

                  <input
                    type="text"
                    placeholder="Write a comment..."
                    value={commentText[post._id] || ""}
                    onChange={(e) =>
                      setCommentText({
                        ...commentText,
                        [post._id]: e.target.value,
                      })
                    }
                  />

                  <button onClick={() => handleComment(post._id)}>
                    💬 Post
                  </button>

                </div>

              </div>
            ))}

          </div>
        </section>

      </main>

      {/* FOOTER */}
      <footer>
        <div className="footer-content">
          <span>📧 email: deveraclaire00@gmail.com</span>
          <span>© 2026 Claire Denise De Vera - Student Portfolio Project</span>
        </div>
      </footer>
    </>
  );
}
